import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend, LineChart, Line, CartesianGrid } from 'recharts';
import { useNavigate } from 'react-router-dom';

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('/fees/dashboard').then(r => setStats(r.data)).catch(console.error).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen" style={{ height:300 }}><div className="spinner" /></div>;
  if (!stats) return <div className="alert alert-error">Failed to load dashboard</div>;

  const fmt = n => `₹${Number(n||0).toLocaleString('en-IN')}`;
  const total = stats.summary.collected + stats.summary.pending + stats.summary.overdue;
  const collectionRate = total > 0 ? Math.round((stats.summary.collected / total) * 100) : 0;

  const pieData = [
    { name: 'Collected', value: stats.summary.collected, color: '#10b981' },
    { name: 'Pending', value: stats.summary.pending, color: '#f59e0b' },
    { name: 'Overdue', value: stats.summary.overdue, color: '#ef4444' },
  ].filter(d => d.value > 0);

  const routeBarData = (stats.routeStats || []).map(r => ({
    name: r.route?.routeNumber || 'N/A',
    collected: parseFloat(r.dataValues?.totalCollected || 0),
    students: parseInt(r.dataValues?.count || 0),
  }));

  return (
    <div>
      {/* Stats */}
      <div className="stats-grid">
        {[
          { label:'Total Students', value: stats.totalStudents, icon:'👨‍🎓', cls:'blue', sub:'Active enrollments' },
          { label:'Active Routes', value: stats.totalRoutes, icon:'🗺️', cls:'purple', sub:'Bus routes' },
          { label:'Fees Collected', value: fmt(stats.summary.collected), icon:'✅', cls:'green', sub:`${stats.paidCount} payments` },
          { label:'Pending Fees', value: fmt(stats.summary.pending), icon:'⏳', cls:'yellow', sub:`${stats.pendingCount} students` },
          { label:'Overdue Fees', value: fmt(stats.summary.overdue), icon:'⚠️', cls:'red', sub:'Needs attention' },
          { label:'Collection Rate', value: `${collectionRate}%`, icon:'📈', cls:'', sub:'This month' },
        ].map(s => (
          <div key={s.label} className={`stat-card ${s.cls}`}>
            <span className="stat-icon">{s.icon}</span>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
            <div className="stat-sub">{s.sub}</div>
            {s.label === 'Collection Rate' && (
              <div className="progress-bar" style={{ marginTop:10 }}>
                <div className={`progress-fill ${collectionRate >= 80 ? 'progress-green' : collectionRate >= 50 ? 'progress-yellow' : 'progress-red'}`} style={{ width:`${collectionRate}%` }} />
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Quick Actions */}
      <div style={{ marginBottom:24 }}>
        <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', marginBottom:12, textTransform:'uppercase', letterSpacing:1 }}>Quick Actions</div>
        <div className="quick-actions">
          {[
            { icon:'➕', label:'Add Student', action: () => navigate('/admin/students') },
            { icon:'⚡', label:'Generate Fees', action: () => navigate('/admin/fees') },
            { icon:'⏰', label:'Upcoming Dues', action: () => navigate('/admin/upcoming') },
            { icon:'⚠️', label:'Overdue List', action: () => navigate('/admin/overdue') },
            { icon:'📅', label:'Schedules', action: () => navigate('/admin/schedules') },
            { icon:'🗺️', label:'Add Route', action: () => navigate('/admin/routes') },
          ].map(a => (
            <div key={a.label} className="quick-action" onClick={a.action}>
              <span className="icon">{a.icon}</span>
              <span>{a.label}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="charts-grid">
        {/* Pie Chart */}
        {pieData.length > 0 && (
          <div className="card">
            <div className="card-header">
              <h3 className="card-title">📊 Fee Collection Status</h3>
              <span style={{ fontSize:12, color:'var(--text-muted)', background:'var(--surface2)', padding:'4px 10px', borderRadius:20, border:'1px solid var(--border)' }}>{stats.currentMonth}</span>
            </div>
            <ResponsiveContainer width="100%" height={240}>
              <PieChart>
                <Pie data={pieData} cx="50%" cy="50%" innerRadius={65} outerRadius={95} paddingAngle={4} dataKey="value">
                  {pieData.map((e, i) => <Cell key={i} fill={e.color} />)}
                </Pie>
                <Tooltip formatter={v => fmt(v)} />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
            <div style={{ textAlign:'center', marginTop:8 }}>
              <div style={{ fontSize:22, fontWeight:800, color:'var(--success)' }}>{collectionRate}%</div>
              <div style={{ fontSize:12, color:'var(--text-muted)' }}>Collection Rate</div>
            </div>
          </div>
        )}

        {/* Bar Chart */}
        {routeBarData.length > 0 && (
          <div className="card">
            <div className="card-header"><h3 className="card-title">🗺️ Collection by Route</h3></div>
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={routeBarData} margin={{ top:5, right:10, bottom:5, left:10 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                <XAxis dataKey="name" tick={{ fontSize:12 }} />
                <YAxis tick={{ fontSize:12 }} />
                <Tooltip formatter={v => fmt(v)} />
                <Bar dataKey="collected" fill="#2563eb" radius={[6,6,0,0]} name="Collected" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>

      {/* Route Summary Table */}
      <div className="card" style={{ marginTop:20 }}>
        <div className="card-header">
          <h3 className="card-title">🚌 Route-wise Summary — {stats.currentMonth}</h3>
          <button className="btn btn-outline btn-sm" onClick={() => navigate('/admin/fees')}>View All Fees →</button>
        </div>
        {routeBarData.length === 0 ? (
          <div className="empty-state"><span className="icon">📭</span><h3>No fee data yet</h3><p>Generate fees for this month to see summary</p></div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead><tr><th>Route</th><th>Students Paid</th><th>Amount Collected</th><th>Status</th></tr></thead>
              <tbody>
                {routeBarData.map((r, i) => (
                  <tr key={i}>
                    <td><strong style={{ background:'#dbeafe', color:'#1d4ed8', padding:'3px 10px', borderRadius:20, fontSize:12 }}>{r.name}</strong></td>
                    <td>{r.students} students</td>
                    <td><strong style={{ color:'var(--success)', fontSize:15 }}>{fmt(r.collected)}</strong></td>
                    <td><span className="badge badge-paid">✅ Collected</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
